const data = $input.first().json;
const reports = data.reports || [];

// Time-weighted density: recent reports count more
const now = Date.now();
const recentReports = reports.filter(r => {
  const age = now - new Date(r.created_at || Date.now()).getTime();
  return age < 30 * 60 * 1000; // Last 30 minutes
});

const injuries = reports.filter(r => r.custom_fields?.injuriesReported === true);
const largeCrowd = reports.filter(r => r.custom_fields?.crowdSize === 'large');
const policeRequired = reports.filter(r => r.custom_fields?.policeRequired === true);
const critical = reports.filter(r => r.severity === 'Critical');

let severity = 'Low';
let probability = 0.05;
let shouldAlert = false;
let message = '';

if ((injuries.length >= 2) || (injuries.length >= 1 && largeCrowd.length >= 1)) {
  severity = 'Critical';
  probability = 0.92;
  shouldAlert = true;
  message = `MAJOR PUBLIC SAFETY INCIDENT: ${injuries.length} injury report(s). Large crowd involvement: ${largeCrowd.length > 0}. Emergency services required.`;
} else if (critical.length >= 1 || (policeRequired.length >= 2)) {
  severity = 'High';
  probability = 0.75;
  shouldAlert = true;
  message = `${reports.length} public safety reports. ${critical.length} critical. Police required: ${policeRequired.length} reports.`;
} else if (recentReports.length >= 5 || reports.length >= 8) {
  severity = 'Medium';
  probability = 0.50;
  shouldAlert = true;
  message = `Elevated public safety reports: ${reports.length} total, ${recentReports.length} in last 30 minutes.`;
} else if (recentReports.length >= 2) {
  severity = 'Low';
  probability = 0.20;
  shouldAlert = false;
}

return [{ json: {
  incidentType: 'public_safety_incident',
  severity,
  probability,
  reportCount: reports.length,
  recentReports: recentReports.length,
  injuryReports: injuries.length,
  largeCrowdReports: largeCrowd.length,
  policeRequired: policeRequired.length,
  message,
  shouldAlert,
  timestamp: new Date().toISOString()
}}];
